SELECT

FROM notice_board board

WHERE 1=1

    AND board.board_type = #{boardType}


    AND board.board_title LIKE '%' || #{boardTitle} || '%'


    AND board.board_content LIKE '%' || #{boardContent} || '%'


    AND board.use_yn = #{useYn}


    AND board.main_yn = #{mainYn}


    AND board.board_auth_type = #{boardAuthType}


    AND board.security_level = #{securityLevel}


    AND (


            board.board_title LIKE '%' || #{searchWord} || '%'



            board.board_content LIKE '%' || #{searchWord} || '%'



            board.board_title LIKE '%' || #{searchWord} || '%'
            OR board.board_content LIKE '%' || #{searchWord} || '%'


    )

SELECT

FROM notice_board board

WHERE board.board_key = #{boardKey}
